import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { Info } from '@mui/icons-material';
import response from './response.json';

interface Departure {
  airport: string;
  time: string;
  gate: string;
}

interface Arrival {
  airport: string;
  time: string;
  gate: string;
}

interface FlightData {
  flightNumber: string;
  departure: Departure;
  arrival: Arrival;
  status: string;
  delay: {
    minutes: number;
  };
}

export default function Widget() {
  const flightData = response.data as FlightData;
  const isOnTime = flightData.status === "On Time";

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 400, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              Flight Number
            </Typography>
            <Typography variant="h5" fontWeight={600} sx={{ color: '#007BFF', mb: 1 }}>
              {flightData.flightNumber}
            </Typography>
            <Stack direction="row" alignItems="center" spacing={1}>
              <Typography variant="body2" sx={{ color: isOnTime ? '#10B981' : '#EF4444', fontWeight: 500 }}>
                {flightData.status}
              </Typography>
              {!isOnTime && (
                <Chip
                  icon={<Info sx={{ fontSize: 16 }} />}
                  label={`${flightData.delay.minutes} mins delay`}
                  sx={{ fontSize: '11px', bgcolor: '#FFEBEE', color: '#EF4444' }}
                />
              )}
            </Stack>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ mb: 0.5, color: '#1976D2' }}>
              Departure
            </Typography>
            <Typography variant="body2" fontWeight={500}>
              {flightData.departure.airport} Airport
            </Typography>
            <Typography variant="caption" color="text.secondary">
              {flightData.departure.time} | Gate {flightData.departure.gate}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ mb: 0.5, color: '#FF5733' }}>
              Arrival
            </Typography>
            <Typography variant="body2" fontWeight={500}>
              {flightData.arrival.airport} Airport
            </Typography>
            <Typography variant="caption" color="text.secondary">
              {flightData.arrival.time} | Gate {flightData.arrival.gate}
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
